// Format search results as context for AutoResearchClaw
const results = $input.first().json;
const memories = results.results || results.data || [];

// Categorize by type
const papers = memories.filter(m => m.metadata?.type === 'paper_draft' || m.metadata?.type === 'synthesis');
const citations = memories.filter(m => m.metadata?.type === 'citation');
const experiments = memories.filter(m => m.metadata?.type === 'experiment_result');
const lessons = memories.filter(m => m.metadata?.type === 'lesson_learned');
const other = memories.filter(m => !['paper_draft','synthesis','citation','experiment_result','lesson_learned'].includes(m.metadata?.type));

const context = {
  total_memories: memories.length,
  categories: {
    papers: papers.length,
    citations: citations.length,
    experiments: experiments.length,
    lessons: lessons.length,
    other: other.length
  },
  // High-priority context for LLM injection
  prior_research: papers.map(m => ({
    content: m.name || m.content || m.summary,
    salience: m.salience,
    run_id: m.metadata?.run_id,
    topic: m.metadata?.topic
  })),
  known_citations: citations.map(m => ({
    content: m.name || m.content,
    salience: m.salience
  })).slice(0, 30),
  experiment_insights: experiments.map(m => ({
    content: m.name || m.content,
    salience: m.salience,
    topic: m.metadata?.topic
  })),
  lessons_learned: lessons.map(m => ({
    content: m.name || m.content,
    severity: m.metadata?.severity,
    salience: m.salience
  })),
  additional_knowledge: other.slice(0, 10).map(m => ({
    content: m.name || m.content,
    salience: m.salience
  }))
};

return [{ json: context }];
